// ✅ Correct path (NO [0])
const raw = $json?.content?.parts?.[0]?.text;

// Debug (optional)
if (!raw) {
  return [{
    json: {
      error: "No AI response found",
      original: $json
    }
  }];
}

// Extract JSON safely
const match = raw.match(/\{[\s\S]*\}/);

let parsed = {};

if (match) {
  try {
    parsed = JSON.parse(match[0]);
  } catch (e) {
    parsed = {};
  }
}

// Normalize
const sentiment = parsed.sentiment?.toLowerCase() || "unknown";

// Return clean data
return [
  {
    json: {
      sentiment,
      topic: parsed.topic || "unknown",
      confidence: parsed.confidence || 0,
      message: $node["Facebook Mention Received"].json.message,
      user_name: $node["Facebook Mention Received"].json.from.name,
      created_time: new Date($node["Facebook Mention Received"].json.created_time).toISOString()
    }
  }
];

